public class Solution {
    private boolean isPalindromeUtility(String s, int start, int end) {
        while (start < end) {
            if (s.charAt(start) != s.charAt(end)) return false;
            start++; end--;
        }
        return true;
    }

    public boolean checkPartitioning(String s) {
        int n = s.length();
        for (int i = 0; i < n - 2; ++i)
            if (isPalindromeUtility(s, 0, i))
                for (int j = i + 1; j < n - 1; ++j)
                    if (isPalindromeUtility(s, i + 1, j) && isPalindromeUtility(s, j + 1, n - 1))
                        return true;
        return false;
    }
}

public class X {
    private void interleaveQueues(Queue<Character> letters, Queue<Character> digits, StringBuilder result) {
        while (!letters.isEmpty() || !digits.isEmpty()) {
            if (!letters.isEmpty()) result.append(letters.poll());
            if (!digits.isEmpty()) result.append(digits.poll());
        }
    }

    public String reformat(String s) {
        Queue<Character> letters = new LinkedList<>();
        Queue<Character> digits = new LinkedList<>();
        for (char c : s.toCharArray()) {
            if (Character.isLetter(c)) letters.add(c);
            else digits.add(c);
        }
        if (Math.abs(letters.size() - digits.size()) > 1) return "";
        StringBuilder result = new StringBuilder();
        interleaveQueues(letters, digits, result);
        return result.toString();
    }
}

public int findJudge(int n, int[][] trust) {
    int[] trustScores = new int[n + 1];
    for (int[] t : trust) {
        trustScores[t[0]]--;
        trustScores[t[1]]++;
    }
    for (int i = 1; i <= n; i++)
        if (trustScores[i] == n - 1) return i;
    return -1;
}

public int uniquePathsWithObstacles(int[][] grid) {
    int rowCount = grid.length;
    int colCount = grid[0].length;
    if (grid[0][0] == 1) return 0;
    grid[0][0] = 1;
    for (int i = 1; i < rowCount; ++i)
        grid[i][0] = (grid[i][0] == 0 && grid[i-1][0] == 1) ? 1 : 0;
    for (int j = 1; j < colCount; ++j)
        grid[0][j] = (grid[0][j] == 0 && grid[0][j-1] == 1) ? 1 : 0;
    for (int i = 1; i < rowCount; ++i)
        for (int j = 1; j < colCount; ++j)
            if (grid[i][j] == 0)
                grid[i][j] = grid[i-1][j] + grid[i][j-1];
    return grid[rowCount-1][colCount-1];
}

public int distinctIntegersAfterReversingAndAdding(int[] nums) {
    Set<Integer> distinct = new HashSet<>();

    // Add original numbers to the set
    for (int num : nums) {
        distinct.add(num);
    }

    // Reverse each number and add it to the set
    for (int num : nums) {
        int reversed = 0;
        while (num > 0) {
            reversed = reversed * 10 + num % 10;
            num /= 10;
        }
        distinct.add(reversed);
    }

    return distinct.size();
}

public List<Integer> grayCode(int n) {
    List<Integer> result = new ArrayList<>();

    // Initialize the first element
    int current = 0;
    result.add(current);

    for (int i = 1; i < (1 << n); i++) {
        // Calculate the next Gray code by XORing with its previous value shifted right by one bit
        current ^= (current >> 1);

        // Add the new Gray code to the list
        result.add(current);
    }

    return result;
}

